class Solution:
    def generateParenthesis(self, n):
        from itertools import product
        def valid(s):
            bal = 0
            for ch in s:
                bal += 1 if ch == '(' else -1
                if bal < 0:
                    return False
            return bal == 0
        res = []
        for combo in product('()', repeat=2 * n):
            s = ''.join(combo)
            if valid(s):
                res.append(s)
        return res

