class Solution:
    def generateParenthesis(self, n):
        res = []
        def bt(cur, opens, closes):
            if len(cur) == 2 * n:
                res.append(cur)
                return
            if opens < n:
                bt(cur + '(', opens + 1, closes)
            if closes < opens:
                bt(cur + ')', opens, closes + 1)
        bt('', 0, 0)
        return res

